+import com.github.javaparser.ast.expr.Expression;
+import com.github.javaparser.ast.expr.MethodCallExpr;
+import com.github.javaparser.ast.expr.ObjectCreationExpr;
+import com.github.javaparser.ast.expr.TypeExpr;
+import com.github.javaparser.ast.visitor.ModifierVisitor;
+import com.github.javaparser.printer.lexicalpreservation.LexicalPreservingPrinter;
+
+import java.io.IOException;
+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.nio.file.Paths;
+import java.util.Comparator;
+import java.util.Optional;
+
 public class Main {
     public static void main(String[] args) {
-
+        if (args.length != 1) {
+            throw new IllegalArgumentException("Usage: Main <source-root>");
+        }
+
+        Path sourceRoot = Paths.get(args[0]);
+        if (!Files.isDirectory(sourceRoot)) {
+            throw new IllegalArgumentException("Not a directory: " + sourceRoot);
+        }
+
+        try {
+            Files.walk(sourceRoot)
+                    .filter(path -> path.toString().endsWith(".java"))
+                    .sorted(Comparator.naturalOrder())
+                    .forEach(Main::rewriteFile);
+        } catch (IOException e) {
+            throw new RuntimeException(e);
+        }
     }
+
+    private static void rewriteFile(Path file) {
+        try {
+            CompilationUnit cu = StaticJavaParser.parse(file);
+            LexicalPreservingPrinter.setup(cu);
+
+            boolean changed = cu.accept(new ReadValueStringToReaderVisitor(), null);
+            if (changed) {
+                ensureStringReaderImport(cu);
+                Files.writeString(file, LexicalPreservingPrinter.print(cu));
+            }
+        } catch (IOException e) {
+            throw new RuntimeException("Failed to rewrite " + file, e);
+        }
+    }
+
+    private static void ensureStringReaderImport(CompilationUnit cu) {
+        boolean hasImport = cu.getImports().stream()
+                .map(ImportDeclaration::getNameAsString)
+                .anyMatch("java.io.StringReader"::equals);
+        if (!hasImport) {
+            cu.addImport(StringReader.class);
+        }
+    }
+
+    private static final class ReadValueStringToReaderVisitor extends ModifierVisitor<Void> {
+        @Override
+        public Visitable visit(MethodCallExpr call, Void arg) {
+            super.visit(call, arg);
+
+            if (!"readValue".equals(call.getNameAsString()) || call.getArguments().size() != 2) {
+                return call;
+            }
+
+            Expression firstArg = call.getArgument(0);
+            Expression secondArg = call.getArgument(1);
+            if (!(secondArg instanceof ClassExpr)) {
+                return call;
+            }
+
+            MethodCallExpr replacement = new MethodCallExpr(
+                    call.getScope().orElse(null),
+                    "readerFor",
+                    NodeList.nodeList(secondArg.clone())
+            );
+            replacement.setArguments(NodeList.nodeList(
+                    new ObjectCreationExpr(null, StaticJavaParser.parseType(StringReader.class.getCanonicalName()),
+                            NodeList.nodeList(firstArg.clone()))
+            ));
+            return replacement;
+        }
+    }
 }
